<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Serialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Deserialize</span><span style="color:#9399B2;">)]</span></span>
